const output = [];

for (const item of $input.all()) {
  const d = item.json;

  // Hacker News: API returns one item with a .hits array
  if (d.hits && Array.isArray(d.hits)) {
    for (const h of d.hits) {
      if (!h.title) continue;
      output.push({
        json: {
          title: h.title,
          description: (h.story_text || '').replace(/<[^>]+>/g, '').slice(0, 500),
          url: h.url || ('https://news.ycombinator.com/item?id=' + h.objectID),
          source: 'hackernews',
          score: h.points || 0,
          content_id: 'hn_' + h.objectID,
          timestamp: new Date().toISOString()
        }
      });
    }
    continue;
  }

  // GitHub: API returns one item with an .items array
  if (d.items && Array.isArray(d.items) && d.items[0] && d.items[0].full_name) {
    for (const r of d.items) {
      output.push({
        json: {
          title: r.full_name + ': ' + (r.description || 'No description'),
          description: r.description || '',
          url: r.html_url,
          source: 'github',
          score: r.stargazers_count || 0,
          content_id: 'gh_' + r.id,
          timestamp: new Date().toISOString()
        }
      });
    }
    continue;
  }

  // RSS: rssFeedRead node outputs individual feed entries
  if (d.title && (d.link || d.guid)) {
    output.push({
      json: {
        title: d.title,
        description: (d.contentSnippet || d.content || d.summary || '').replace(/<[^>]+>/g, '').slice(0, 500),
        url: d.link || d.guid,
        source: 'rss',
        score: 0,
        content_id: 'rss_' + Date.now() + '_' + Math.random().toString(36).substr(2, 6),
        timestamp: new Date().toISOString()
      }
    });
  }
}

return output.length > 0 ? output : $input.all();

// Merge Ollama embedding response back with the original item data
const ollamaResp = $input.first().json;
const originalItem = $('Split In Batches').item.json;

return [{
  json: Object.assign({}, originalItem, {
    embedding: ollamaResp.embedding || []
  })
}];

// Determine if this content is a duplicate (similarity >= 0.85)
const searchResp = $input.first().json;
const item = $('Attach Embedding to Item').item.json;

const results = searchResp.result || [];
const maxScore = results.length > 0 ? results[0].score : 0;
const isDuplicate = maxScore >= 0.85;

return [{
  json: Object.assign({}, item, {
    maxScore: maxScore,
    isDuplicate: isDuplicate
  })
}];

// Qdrant upsert replaces item data with its ACK response.
// Restore original item from the upstream node.
const item = $('Evaluate Similarity').item.json;
return [{ json: Object.assign({}, item, { qdrant_stored: true }) }];

const scoutResp = $input.first().json;
const item = $('Restore Data After Upsert').item.json;

const content = (scoutResp.message && scoutResp.message.content)
  ? scoutResp.message.content
  : (scoutResp.response || '');

var verdict = 'IGNORE';
try {
  var m = content.match(/\{[^{}]+\}/);
  if (m) {
    var parsed = JSON.parse(m[0]);
    verdict = (parsed.verdict || '').toUpperCase() === 'POST' ? 'POST' : 'IGNORE';
  } else if (content.toUpperCase().indexOf('"POST"') !== -1 || content.toUpperCase().indexOf(':POST') !== -1) {
    verdict = 'POST';
  }
} catch(e) {
  verdict = 'IGNORE';
}

return [{
  json: Object.assign({}, item, {
    scout_verdict: verdict,
    scout_raw: content.slice(0, 200)
  })
}];

const stratResp = $input.first().json;
const item = $('Parse Scout Response').item.json;

const content = (stratResp.message && stratResp.message.content)
  ? stratResp.message.content
  : (stratResp.response || '');

var hook = '';
var insight = '';
var implication = '';

try {
  var m = content.match(/\{[\s\S]*?\}/);
  if (m) {
    var parsed = JSON.parse(m[0]);
    hook = parsed.hook || '';
    insight = parsed.insight || '';
    implication = parsed.implication || '';
  }
} catch(e) {}

return [{
  json: Object.assign({}, item, {
    hook: hook || item.title,
    insight: insight || (item.description ? item.description.slice(0, 280) : 'Key development in the AI space.'),
    implication: implication || 'Worth tracking for AI engineers and builders.'
  })
}];

const item = $input.first().json;

// LinkedIn Post (long-form, ~300 words)
var linkedinPost = 'Most people will miss this.\n\n' +
  item.hook + '\n\n' +
  "Here's the real shift:\n" +
  '-> ' + item.insight + '\n\n' +
  'What this enables:\n' +
  '* ' + item.implication + '\n\n' +
  'Source: ' + item.url + '\n\n' +
  '#AI #MachineLearning #AIEngineering #LLM #AIAgents #BuildInPublic';

// X/Twitter Post (280 char max)
var xFull = item.hook + '\n\n-> ' + item.insight + '\n\n' + item.url + ' #AI #ML';
var xPost = xFull.length > 280 ? xFull.slice(0, 277) + '...' : xFull;

var postId = 'post_' + Date.now() + '_' + Math.random().toString(36).substr(2, 6);

var approvalMsg = '[NEW POST READY FOR APPROVAL]\n\n' +
  'Source: ' + item.source.toUpperCase() + '\n' +
  'Title: ' + item.title.slice(0, 120) + '\n' +
  'Scout: ' + item.scout_verdict + '\n\n' +
  '=== LINKEDIN DRAFT ===\n' + linkedinPost + '\n\n' +
  '=== X/TWITTER DRAFT ===\n' + xPost + '\n\n' +
  'Post ID: ' + postId;

return [{
  json: Object.assign({}, item, {
    linkedinPost: linkedinPost,
    xPost: xPost,
    postId: postId,
    approvalMessage: approvalMsg
  })
}];
